--
-- Table structure for table `transactions`
--

DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transactions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `date` date NOT NULL,
  `serial_no` int NOT NULL,
  `customer_name` varchar(100) DEFAULT NULL,
  `mobile` varchar(15) DEFAULT NULL,
  `product_desc` varchar(300) NOT NULL,
  `amount` decimal(10,2) DEFAULT '0.00',
  `cash` decimal(10,2) DEFAULT '0.00',
  `gpay` decimal(10,2) DEFAULT '0.00',
  `vmp_cost` decimal(10,2) DEFAULT '0.00' COMMENT 'Profit margin on this transaction',
  `sales_amount` decimal(10,2) DEFAULT '0.00',
  `service_amount` decimal(10,2) DEFAULT '0.00',
  `entered_by` int DEFAULT NULL COMMENT 'FK → users.id',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `transactions_date` (`date`),
  KEY `transactions_mobile` (`mobile`),
  KEY `transactions_customer_name` (`customer_name`),
  KEY `entered_by` (`entered_by`),
  CONSTRAINT `transactions_ibfk_1` FOREIGN KEY (`entered_by`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3179 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

